import{_ as a,o as n,c as i,a7 as e}from"./chunks/framework.BPD8m7Vq.js";const b=JSON.parse('{"title":"🚀 个人项目架构大重构：从“手动拖拽”到 CI/CD “自动化魔法”的极客进化史 ✨","description":"","frontmatter":{},"headers":[],"relativePath":"面试笔记/MyWeb/构建过程end.md","filePath":"面试笔记/MyWeb/构建过程end.md","lastUpdated":1775274072000}'),l={name:"面试笔记/MyWeb/构建过程end.md"};function p(t,s,r,o,d,c){return n(),i("div",null,[...s[0]||(s[0]=[e(`<h1 id="🚀-个人项目架构大重构-从-手动拖拽-到-ci-cd-自动化魔法-的极客进化史-✨" tabindex="-1">🚀 个人项目架构大重构：从“手动拖拽”到 CI/CD “自动化魔法”的极客进化史 ✨ <a class="header-anchor" href="#🚀-个人项目架构大重构-从-手动拖拽-到-ci-cd-自动化魔法-的极客进化史-✨" aria-label="Permalink to &quot;🚀 个人项目架构大重构：从“手动拖拽”到 CI/CD “自动化魔法”的极客进化史 ✨&quot;">​</a></h1><div class="tech-impact-cover"><p class="tech-impact-cover__kicker">CI/CD ARCHITECTURE REBUILD</p><h2>把部署从体力活，重构成一条可持续进化的工程流水线</h2><p class="tech-impact-cover__lead">这不是一次普通的“部署优化”，而是一场完整的工程体系升级。目标是让每次提交都能稳定落地，让创作与交付之间不再有摩擦。</p><div class="tech-impact-cover__grid"><div class="tech-impact-cover__stat"><strong>4</strong><span>核心故障 BOSS</span></div><div class="tech-impact-cover__stat"><strong>3</strong><span>关键系统组件</span></div><div class="tech-impact-cover__stat"><strong>1</strong><span>推送即部署链路</span></div><div class="tech-impact-cover__stat"><strong>∞</strong><span>可复用工程资产</span></div></div><div class="tech-impact-cover__actions"><a href="#battle-log">进入打怪日志</a><a href="#final-arsenal">查看终极配置</a></div></div><h2 id="🎸-引言-告别刀耕火种-迎接赛博黎明-🔥" tabindex="-1">🎸 引言：告别刀耕火种，迎接赛博黎明 🔥 <a class="header-anchor" href="#🎸-引言-告别刀耕火种-迎接赛博黎明-🔥" aria-label="Permalink to &quot;🎸 引言：告别刀耕火种，迎接赛博黎明 🔥&quot;">​</a></h2><p>每一个在键盘上挥洒汗水的开发者，绝对都曾经历过那段被称为**“手动拖拽”的黑暗时期**。</p><p>回想一下那个令人窒息的场景：你明明只是在知识库里修改了一个微不足道的错别字，却不得不心情沉重地打开终端，敲下枯燥的 <code>npm run build</code>。接着，你要像一个做苦力的搬运工一样，打开 FTP 或 SSH 工具，小心翼翼地把打包好的 <code>dist</code> 文件夹拖拽到远程服务器上，替换旧文件，然后眼巴巴地看着进度条缓慢爬行。</p><p>这不仅无聊透顶、疯狂消耗创作热情，更可怕的是，这种“原始操作”充满了致命的危机——万一手抖拖错了目录，或者不小心覆盖了重要的 Nginx 配置文件，整个网站当场白屏（502 Bad Gateway 警告！🚨）。这哪里是在部署代码？这简直就是在进行一场惊心动魄的“技术性赌博”🎰！</p><p>但是，作为一名追求极致的工程师，怎么能容忍自己把宝贵的生命浪费在无意义的重复劳动上呢？</p><h3 id="🎯-终极愿景-基础设施即代码-iac" tabindex="-1">🎯 终极愿景：基础设施即代码 (IaC) <a class="header-anchor" href="#🎯-终极愿景-基础设施即代码-iac" aria-label="Permalink to &quot;🎯 终极愿景：基础设施即代码 (IaC)&quot;">​</a></h3><p><strong>“写完笔记，只需一次 <code>git push</code>，剩下的统统交给魔法！”</strong> 🎩✨</p><p>没错！这就是现代软件工程的最高奥义——自动化流水线 (CI/CD)。从今往后，不再有战战兢兢的手动拖拽，只要将灵感推送到远端，系统就会像一个不知疲倦的齿轮，自动完成拉取、构建、测试与部署的华丽交响乐！</p><hr><h2 id="🌍-全局架构设计-流动的赛博管线" tabindex="-1">🌍 全局架构设计：流动的赛博管线 <a class="header-anchor" href="#🌍-全局架构设计-流动的赛博管线" aria-label="Permalink to &quot;🌍 全局架构设计：流动的赛博管线&quot;">​</a></h2><p>在开始我们的“打怪史诗”之前，先带你俯瞰一下这套被爆改后的现代化 CI/CD 系统。这就好比一场完美的 Live 演出，每个环节都必须严丝合缝！</p><p><strong>🎵 工作流全景解析：</strong></p><ol><li><strong>✍️ Obsidian 本地写作（灵感发源地）</strong>：在本地使用 Obsidian 完成笔记的创作。Obsidian 强大的双向链接和层级结构，是知识库的灵魂。这里就像是我们的地下排练室，随心所欲地挥洒创意。</li><li><strong>☁️ GitHub 托管（版本控制中枢）</strong>：写完后，<code>git push</code> 将所有 Markdown 笔记同步至 GitHub 仓库。这里是安全的金库，记录着每一次思想的闪光。</li><li><strong>⚡ GitHub Actions 自动化流水线（魔法驱动引擎）</strong>：代码刚刚抵达 GitHub，Webhook 瞬间触发！GitHub Actions 就像一位尽职的舞台总监，立刻启动预设的脚本，执行自动化构建和部署任务。</li><li><strong>🐳 Docker + Nginx 容器化部署（终极集装箱）</strong>：Actions 自动通过 SSH 登录阿里云服务器，拉取最新代码，唤醒 Docker 引擎重新构建镜像。最后，优雅地替换旧的 Nginx 容器，将崭新的知识库呈现给全世界。</li></ol><p>一切都在后台默默发生，流畅如水，这就是工程师独有的浪漫！🔥</p><h2 id="🕒-版本时间线-v1-v2-v3-v4" tabindex="-1">🕒 版本时间线（v1 / v2 / v3 / v4） <a class="header-anchor" href="#🕒-版本时间线-v1-v2-v3-v4" aria-label="Permalink to &quot;🕒 版本时间线（v1 / v2 / v3 / v4）&quot;">​</a></h2><p>为了让演进路径更清晰，这里用一次“里程碑回放”总结从落地到演进的四个阶段：</p><table tabindex="0"><thead><tr><th>版本</th><th>时间</th><th>关键变化</th><th>典型问题</th><th>阶段结论</th></tr></thead><tbody><tr><td><strong>v1 手工部署期</strong></td><td>2026-03 初</td><td>本地构建后手动上传服务器</td><td>流程重复、容易误操作、回滚困难</td><td>可用但不可持续</td></tr><tr><td><strong>v2 自动化拉取期</strong></td><td>2026-03 中后</td><td>GitHub Actions 触发，服务器 <code>git pull</code> + 构建部署</td><td>受公网访问 GitHub 稳定性影响，偶发超时</td><td>自动化已成型，但链路脆弱</td></tr><tr><td><strong>v3 增量同步期（当前）</strong></td><td>2026-04</td><td>迁移腾讯云；CI 先构建，再 <code>rsync</code> 增量下发 <code>dist</code>；图片资源构建前自动准备</td><td>早期图片路径与资源缺失问题已被流程兜底</td><td>稳定性与可维护性显著提升</td></tr><tr><td><strong>v4 规划期（下一阶段）</strong></td><td>2026-Q2 规划</td><td>引入“页面编辑模式”（可视化增删模块、拖拽缩放、样式参数调节）、主题配置持久化、发布前预览校验</td><td>交互状态复杂度上升、编辑与展示模式隔离要求更高</td><td>从“工程自动化”迈向“可视化内容运营”</td></tr></tbody></table><p><strong>一句话理解 v3：</strong> 从“服务器自己拉代码并构建”，升级为“CI 产物直达服务器并增量同步”。部署更快、链路更稳、排障更简单。</p><p><strong>一句话理解 v4：</strong> 在不牺牲现有稳定性的前提下，让网站从“开发者改代码”升级为“可视化改页面”。</p><p><strong>v4 执行路线（草案）：</strong></p><ol><li>建立编辑模式开关与权限控制（只对管理员显示）。</li><li>抽象页面区块数据结构（位置、尺寸、颜色、透明度、内容源）。</li><li>接入可视化拖拽/缩放能力并实时预览。</li><li>将配置保存为 JSON（Git 管理或后台存储二选一）。</li><li>增加“发布前校验 + 一键回滚”机制，避免线上样式误改。</li></ol><p><a id="battle-log"></a></p><h2 id="⚔️-炼狱踩坑录-连斩四大技术-boss" tabindex="-1">⚔️ 炼狱踩坑录：连斩四大技术 BOSS <a class="header-anchor" href="#⚔️-炼狱踩坑录-连斩四大技术-boss" aria-label="Permalink to &quot;⚔️ 炼狱踩坑录：连斩四大技术 BOSS&quot;">​</a></h2><p>当然，通往终极浪漫的路上绝对不会一帆风顺。在这场重构中，我遭遇了几个足以让人抓狂的技术难题。但正是这些痛苦的踩坑经历，锻造了强大的工程师思维！</p><h3 id="🛡️-boss-1-权限门卫的无情拒绝-ssh-认证与-linux-权限-🔐" tabindex="-1">🛡️ BOSS 1：权限门卫的无情拒绝 (SSH 认证与 Linux 权限) 🔐 <a class="header-anchor" href="#🛡️-boss-1-权限门卫的无情拒绝-ssh-认证与-linux-权限-🔐" aria-label="Permalink to &quot;🛡️ BOSS 1：权限门卫的无情拒绝 (SSH 认证与 Linux 权限) 🔐&quot;">​</a></h3><p><strong>🔥 战场表现：</strong> 剧本明明写好了，但每次 GitHub Actions 尝试使用 <code>appleboy/ssh-action</code> 登录服务器时，终端就是一片惨红，疯狂报错，连接无情失败。明明 GitHub Secrets 里的配置都对，为什么就是进不去？！</p><p><strong>💡 原理与破局：</strong> 新手往往以为配好密钥就万事大吉，却忽略了 Linux 底层那偏执狂一般的安全机制。如果你的密钥文件权限设置得太“大方”，<code>sshd</code> 会立刻认为“这把钥匙不安全”，然后直接拒之门外。</p><p><strong>🎸 极客斩杀法：</strong> 必须对服务器的权限进行“军管级”的严苛控制：</p><ul><li><code>chmod 700 ~/.ssh</code>：目录权限，只有属主可以读、写、执行。</li><li><code>chmod 600 ~/.ssh/authorized_keys</code>：文件权限，只有属主可以读、写，绝对禁止其他用户访问！ 权限收紧的瞬间，大门轰然敞开，Actions 成功登入！</li></ul><h3 id="🐉-boss-2-被-232mb-巨兽拖垮的流水线-构建上下文溢出-🐉" tabindex="-1">🐉 BOSS 2：被 232MB 巨兽拖垮的流水线 (构建上下文溢出) 🐉 <a class="header-anchor" href="#🐉-boss-2-被-232mb-巨兽拖垮的流水线-构建上下文溢出-🐉" aria-label="Permalink to &quot;🐉 BOSS 2：被 232MB 巨兽拖垮的流水线 (构建上下文溢出) 🐉&quot;">​</a></h3><p><strong>🔥 战场表现：</strong> 执行 <code>docker build</code> 时，终端缓缓吐出：<code>Sending build context to Docker daemon 232.6MB...</code>。随后进度条凝固，几分钟后直接触发 Timeout 崩溃。</p><p><strong>💡 原理与破局：</strong> 这是构建上下文 (Build Context) 溢出的典型惨案。Docker 构建镜像时，会将当前目录下的所有文件发送给 Docker Daemon。如果 <code>.gitignore</code> 配置不当，包含几万个垃圾文件的 <code>node_modules</code> 就会被一起传过去，极其耗时。</p><p><strong>🎸 极客斩杀法：</strong> 实施彻底的“物理超度”：</p><ol><li><strong>清理 Git 缓存</strong>：执行 <code>git rm -r --cached node_modules</code>，将其从版本控制中踢出。</li><li><strong>建立护城河</strong>：在项目根目录严谨地配置 <code>.gitignore</code>。</li><li><strong>服务器大扫除</strong>：在服务器端执行 <code>rm -rf node_modules</code> 清理历史残留。 再次构建，上下文体积骤降，构建速度瞬间起飞！</li></ol><h3 id="🌏-boss-3-跨洋网络的阻击-alpine-源与-npm-镜像超时-🌏" tabindex="-1">🌏 BOSS 3：跨洋网络的阻击 (Alpine 源与 NPM 镜像超时) 🌏 <a class="header-anchor" href="#🌏-boss-3-跨洋网络的阻击-alpine-源与-npm-镜像超时-🌏" aria-label="Permalink to &quot;🌏 BOSS 3：跨洋网络的阻击 (Alpine 源与 NPM 镜像超时) 🌏&quot;">​</a></h3><p><strong>🔥 战场表现：</strong> Docker 构建时，执行 <code>apk add git</code> 和 <code>npm install</code> 网络连接断断续续，最后弹出 <code>network connection aborted</code>。</p><p><strong>💡 原理与破局：</strong> Docker 默认使用的 Alpine Linux 镜像源和 NPM 官方源都远在海外，国内服务器拉取极不稳定。</p><p><strong>🎸 极客斩杀法：</strong> 在 Dockerfile 中植入换源指令：</p><ol><li><strong>替换 Alpine 源</strong>：用 <code>sed</code> 命令将 <code>dl-cdn.alpinelinux.org</code> 瞬间替换为阿里云源 <code>mirrors.aliyun.com</code>。</li><li><strong>更换 NPM 源</strong>：将 NPM 注册表强行切到腾讯云 <code>mirrors.cloud.tencent.com/npm/</code>。 曾经“等到天荒地老”的安装过程，现在变成了电光石火的 3 秒钟！⚡</li></ol><h3 id="🔄-boss-4-vitepress-的傲娇路由与-乾坤大挪移-终极难点-🔄" tabindex="-1">🔄 BOSS 4：VitePress 的傲娇路由与“乾坤大挪移” (终极难点) 🔄 <a class="header-anchor" href="#🔄-boss-4-vitepress-的傲娇路由与-乾坤大挪移-终极难点-🔄" aria-label="Permalink to &quot;🔄 BOSS 4：VitePress 的傲娇路由与“乾坤大挪移” (终极难点) 🔄&quot;">​</a></h3><p><strong>🔥 战场表现：</strong> Rollup 编译第一阶段全绿，但在 <code>rendering pages...</code> 阶段疯狂刷屏报错 <code>ERR_MODULE_NOT_FOUND</code>。Docker 只能拿旧缓存部署，打开网页永远是 Nginx 的蓝屏欢迎页。</p><p><strong>💡 原理与破局：</strong> 在本地 Obsidian 写作时，习惯使用 <code>/images/xxx.png</code> 绝对路径存放图片。但 VitePress 极其严格，规定所有静态资源必须放在根目录的 <code>public</code> 文件夹下，否则服务端渲染 (SSR) 找不到文件直接崩溃。</p><p><strong>面临绝境：手动修改几百篇 Markdown 里的图片路径？</strong> 绝对不行！如果手动去改，极客的尊严就输了！</p><p><strong>🎸 极客斩杀法（核心黑魔法）：</strong> 真正的 DevOps 做法，是让代码适应我们，而不是我们去迁就代码！直接在 <code>Dockerfile</code> 里动刀子，在执行 <code>vitepress build</code> 命令之前，加入一行优雅的 Bash 脚本：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">RUN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-knowledge-base/docs/public</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    cp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-knowledge-base/images</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-knowledge-base/docs/public/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这就是赛博时代的“偷梁换柱”！让机器人在流水线中自动把图片拷贝过去。本地笔记零修改，依旧享受 Obsidian 的丝滑；云端流水线自动兼容，完美解析！</p><p><a id="final-arsenal"></a></p><h2 id="💥-终极武器库-完美的-dockerfile-配置" tabindex="-1">💥 终极武器库：完美的 Dockerfile 配置 <a class="header-anchor" href="#💥-终极武器库-完美的-dockerfile-配置" aria-label="Permalink to &quot;💥 终极武器库：完美的 Dockerfile 配置&quot;">​</a></h2><p>历经四大 BOSS 的洗礼，终于铸造出了这把“终极圣剑”。这份 <code>Dockerfile</code> 的每一行，都凝聚着踩坑流血换来的经验值！</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># ==========================================</span></span>
<span class="line"><span># 🎵 阶段一：构建阶段 (Builder Stage) - 准备乐器与排练</span></span>
<span class="line"><span># ==========================================</span></span>
<span class="line"><span>FROM node:18-alpine AS builder</span></span>
<span class="line"><span>WORKDIR /app</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 🌟 核心加速 1：替换阿里云镜像源，解决 apk add 跨洋超时难题</span></span>
<span class="line"><span>RUN sed -i &#39;s/dl-cdn.alpinelinux.org/[mirrors.aliyun.com/g](https://mirrors.aliyun.com/g)&#39; /etc/apk/repositories &amp;&amp; \\</span></span>
<span class="line"><span>    apk add --no-cache git</span></span>
<span class="line"><span></span></span>
<span class="line"><span>COPY package.json package-lock.json ./ </span></span>
<span class="line"><span></span></span>
<span class="line"><span># 🌟 核心加速 2：使用国内 NPM 镜像，拒绝网络中断</span></span>
<span class="line"><span>RUN npm config set registry [https://mirrors.cloud.tencent.com/npm/](https://mirrors.cloud.tencent.com/npm/) &amp;&amp; npm install</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 把所有知识库文件拷贝进来</span></span>
<span class="line"><span>COPY . .</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 🌟 核心黑魔法：打包前，自动将图片搬运至 public 目录，完美兼容 Obsidian 绝对路径！</span></span>
<span class="line"><span># 绝不手动改文章！让机器替我们干活！</span></span>
<span class="line"><span>RUN mkdir -p my-knowledge-base/docs/public &amp;&amp; \\</span></span>
<span class="line"><span>    cp -r my-knowledge-base/images my-knowledge-base/docs/public/</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 执行 VitePress 打包命令</span></span>
<span class="line"><span>RUN npx vitepress build my-knowledge-base/docs</span></span>
<span class="line"><span></span></span>
<span class="line"><span># ==========================================</span></span>
<span class="line"><span># 🎤 阶段二：部署阶段 (Deployment Stage) - 正式登台演出</span></span>
<span class="line"><span># ==========================================</span></span>
<span class="line"><span>FROM nginx:alpine</span></span>
<span class="line"><span># 从 builder 阶段提取编译好的纯静态文件，放入 Nginx 容器</span></span>
<span class="line"><span>COPY --from=builder /app/my-knowledge-base/docs/.vitepress/dist /usr/share/nginx/html</span></span>
<span class="line"><span>EXPOSE 80</span></span>
<span class="line"><span># 保持 Nginx 在前台运行</span></span>
<span class="line"><span>CMD [&quot;nginx&quot;, &quot;-g&quot;, &quot;daemon off;&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br></div></div><hr><h2 id="🛰️-后续升级实录-2026-04-从阿里云迁移到腾讯云-图片逻辑再强化" tabindex="-1">🛰️ 后续升级实录（2026-04）：从阿里云迁移到腾讯云 + 图片逻辑再强化 <a class="header-anchor" href="#🛰️-后续升级实录-2026-04-从阿里云迁移到腾讯云-图片逻辑再强化" aria-label="Permalink to &quot;🛰️ 后续升级实录（2026-04）：从阿里云迁移到腾讯云 + 图片逻辑再强化&quot;">​</a></h2><p>在第一版 CI/CD 跑稳之后，又做了一次关键升级，把“可用”进一步推向“稳定”。</p><h3 id="_1-🌩️-服务器从阿里云迁移到腾讯云" tabindex="-1">1) 🌩️ 服务器从阿里云迁移到腾讯云 <a class="header-anchor" href="#_1-🌩️-服务器从阿里云迁移到腾讯云" aria-label="Permalink to &quot;1) 🌩️ 服务器从阿里云迁移到腾讯云&quot;">​</a></h3><p>这次迁移的核心目标，不是“换平台”，而是提升整条发布链路的稳定性与可维护性。</p><p><strong>迁移后当前链路：</strong></p><ol><li>本地 Obsidian 写作并提交到 GitHub。</li><li>GitHub Actions 自动执行构建。</li><li>通过 <code>rsync</code> 增量同步静态产物到腾讯云服务器目录。</li><li>Nginx 直接托管同步后的静态文件。</li></ol><p><strong>这次迁移带来的收益：</strong></p><ul><li>发布路径更直观：从“服务器拉代码构建”切换为“CI 产物直接下发”。</li><li>回滚更容易：每次部署都对应一次明确的构建产物。</li><li>线上更干净：服务器职责聚焦为“提供静态文件服务”，减少环境漂移问题。</li></ul><h3 id="_2-🖼️-图片逻辑升级-构建前自动准备资源-彻底规避旧报错" tabindex="-1">2) 🖼️ 图片逻辑升级：构建前自动准备资源，彻底规避旧报错 <a class="header-anchor" href="#_2-🖼️-图片逻辑升级-构建前自动准备资源-彻底规避旧报错" aria-label="Permalink to &quot;2) 🖼️ 图片逻辑升级：构建前自动准备资源，彻底规避旧报错&quot;">​</a></h3><p>之前出现过经典问题：Markdown 中引用了 <code>/images/...</code>，但构建环境中未准备到 <code>docs/public/images</code>，导致 <code>vitepress build</code> 在 CI 阶段报错中断。</p><p>为避免同类问题再次出现，已将“图片同步”前置到部署工作流，作为构建前的固定步骤：</p><div class="language-yaml vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">- </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Prepare static image assets</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  run</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    mkdir -p my-knowledge-base/docs/public/images</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    cp -a my-knowledge-base/images/. my-knowledge-base/docs/public/images/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>这一步的意义：</strong></p><ul><li>本地写作习惯不变，仍可继续使用统一的图片引用方式。</li><li>CI 环境每次构建都能拿到完整图片资源，避免“本地能跑、线上失败”。</li><li>把“图片路径兼容”从人工记忆变成流水线保障，稳定性显著提升。</li></ul><h3 id="_3-🔁-更换服务器端文件更新方式-从-拉代码-切到-增量同步产物" tabindex="-1">3) 🔁 更换服务器端文件更新方式：从“拉代码”切到“增量同步产物” <a class="header-anchor" href="#_3-🔁-更换服务器端文件更新方式-从-拉代码-切到-增量同步产物" aria-label="Permalink to &quot;3) 🔁 更换服务器端文件更新方式：从“拉代码”切到“增量同步产物”&quot;">​</a></h3><p>这次还做了一个非常关键的部署策略切换：</p><ul><li><strong>旧方式</strong>：服务器 <code>git pull</code> + 本机构建，或者整包上传（耗时且受网络波动影响大）。</li><li><strong>新方式</strong>：GitHub Actions 先构建，再用 <code>rsync</code> 增量同步 <code>dist</code> 到服务器站点目录。</li></ul><p>核心配置思路如下：</p><div class="language-yaml vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">- </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Rsync deploy</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  uses</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">burnett01/rsync-deployments@7.0.2</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  with</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    switches</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">-avzr --delete --omit-dir-times --no-perms --no-owner --no-group</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    path</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">my-knowledge-base/docs/.vitepress/dist/</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    remote_path</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">\${{ secrets.SERVER_DEPLOY_PATH }}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>升级后的实际效果：</strong></p><ul><li>只传变更文件，部署速度明显提升。</li><li><code>--delete</code> 保证服务器目录与本次构建产物严格一致，避免旧文件残留。</li><li>服务器不再依赖访问 GitHub 拉取仓库，降低外网不稳定导致的失败概率。</li></ul><h3 id="_4-🎨-ui-交互升级-从-能看-到-有质感、有状态" tabindex="-1">4) 🎨 UI/交互升级：从“能看”到“有质感、有状态” <a class="header-anchor" href="#_4-🎨-ui-交互升级-从-能看-到-有质感、有状态" aria-label="Permalink to &quot;4) 🎨 UI/交互升级：从“能看”到“有质感、有状态”&quot;">​</a></h3><p>这次并不只是部署链路调整，前端体验也做了一轮完整强化，重点包括：</p><ul><li><p><strong>阅读增强（全站笔记页）</strong></p><ul><li>新增阅读进度条。</li><li>新增章节导航高亮与跟随定位。</li><li>章节导航改为可拖拽，并加入图形化收起/展开控件。</li></ul></li><li><p><strong>首页多风格切换</strong></p><ul><li>新增「常态 / 晶透 / 液态」三种风格切换入口。</li><li>风格切换支持“当前激活态”可视反馈，避免用户不知道当前模式。</li></ul></li><li><p><strong>液态风格专项改造（iOS 灵感）</strong></p><ul><li>首页改为强视觉主标题风格，弱化传统卡片堆叠感。</li><li>引入更通透的玻璃层与背景氛围。</li><li>增加液态播放器（含进度、播放控制、音量、胶囊化控件形态）。</li><li>BGM 改为<strong>非自动播放</strong>，避免进站打扰和浏览器策略拦截。</li></ul></li></ul><h3 id="_5-🧩-交互逻辑修复-解决风格切换串态与残留问题" tabindex="-1">5) 🧩 交互逻辑修复：解决风格切换串态与残留问题 <a class="header-anchor" href="#_5-🧩-交互逻辑修复-解决风格切换串态与残留问题" aria-label="Permalink to &quot;5) 🧩 交互逻辑修复：解决风格切换串态与残留问题&quot;">​</a></h3><p>曾出现过典型“状态串台”问题：从某风格切到另一风格时，旧卡片未清理、BGM 状态残留、页面元素显示错乱。</p><p>这轮修复后，核心策略变为：</p><ul><li>风格切换时执行统一的“进入/退出”清理逻辑。</li><li>按风格独立管理 DOM 与状态，避免相互污染。</li><li>播放器与页面风格绑定，退出对应风格时同步回收相关状态。</li></ul><p>结果是：切换链路更稳定，视觉层级更清爽，整体体验更接近“系统级主题切换”。</p><p>一句话总结：这次升级不是“修一个 bug”，而是把部署系统再往工程化推进了一层。🚀</p><hr><h2 id="💫-结语-自动化的浪漫-💫" tabindex="-1">💫 结语：自动化的浪漫 💫 <a class="header-anchor" href="#💫-结语-自动化的浪漫-💫" aria-label="Permalink to &quot;💫 结语：自动化的浪漫 💫&quot;">​</a></h2><p>呼~ 终于大功告成了！看着绿色的对勾在 GitHub Actions 里亮起，所有的辛苦都值了。</p><p>在这次架构重构中，完成的不仅是从“手工劳作”到“现代工业”的跃升，更是深刻体会到了什么是真正的——<strong>基础设施即代码 (IaC)</strong>。</p><p>自动化不仅仅是为了省下那几分钟的手动拖拽时间，它更是一次对极客精神的致敬。它的意义在于保护“创作心流”——从此以后，可以把 100% 的精力集中在思考、写作和编码上。每次灵感迸发后，只需潇洒地敲下一句 <code>git push</code>，就能安静地看着自动化的魔法在赛博空间里搭建起整座城堡。</p><p>继续前行，探索未来的技术海洋！🌊</p>`,89)])])}const g=a(l,[["render",p]]);export{b as __pageData,g as default};
